{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Conceptual Foundations and Measurement",
      "description": "Equip learners with tools to understand the working of Chemistry, develop conceptual foundations, represent phenomena at macroscopic/molecular/symbolic levels, identify patterns, and apply knowledge to real-life situations.",
      "competencies": [
        "Understand nature of matter, properties, measurement, uncertainty, laws of chemical combination, Dalton's atomic theory",
        "Calculate atomic/molecular masses, mole concept, molar mass, percentage composition, stoichiometry"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Atomic Structure and Quantum Mechanics",
      "description": "Enable learners to comprehend the evolution from sub-atomic particles discovery to quantum mechanical models, identifying patterns in atomic structure.",
      "competencies": [
        "Trace discoveries of sub-atomic particles and development leading to Bohr's model"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Periodicity and Classification",
      "description": "Enable learners to classify elements, understand periodic laws, electronic configurations, block types (s,p,d,f), and trends in properties.",
      "competencies": [
        "Apply modern periodic law and interpret the present form of Periodic Table"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding Theories",
      "description": "Enable learners to represent chemical phenomena at molecular levels using various bonding theories (Kossel-Lewis, VSEPR, Valence Bond, Molecular Orbital).",
      "competencies": [
        "Apply Kossel-Lewis approach and understand Ionic/Electrovalent bonds"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics and Spontaneity",
      "description": "Enable learners to analyze thermodynamic terms, enthalpy changes, calorimetry, spontaneity, Gibbs energy change, and equilibrium conditions.",
      "competencies": [
        "Analyze applications of thermodynamics and measurement of ∆U and ∆H"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Chemical Equilibrium Principles",
      "description": "Enable learners to identify patterns in dynamic equilibrium, apply laws of chemical equilibrium, and understand factors affecting equilibria including ionic equilibrium.",
      "competencies": [
        "Apply Law of Chemical Equilibrium and interpret relationship between K, Q, and Gibbs Energy"
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox Reactions and Electrode Processes",
      "description": "Enable learners to identify oxidation-reduction reactions in terms of electron transfer, assign oxidation numbers, and understand electrode processes.",
      "competencies": [
        "Classify redox reactions based on classical ideas and electron transfer mechanisms"
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry Fundamentals",
      "description": "Enable learners to represent organic compounds structurally, classify them, apply nomenclature rules (IUPAC), understand isomerism and reaction mechanisms.",
      "competencies": [
        "Apply structural representations and classification of organic compounds"
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbon Classification and Properties",
      "description": "Enable learners to classify hydrocarbons, understand properties of alkanes, alkenes, alkynes, aromatic compounds, and assess carcinogenic/toxicity issues.",
      "competencies": [
        "Differentiate between types of hydrocarbons based on structure and bonding"
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solution Chemistry and Colligative Properties",
      "description": "Enable learners to express concentration, understand solubility, vapor pressure, ideal/non-ideal solutions, and determine molar mass via colligative properties.",
      "competencies": [
        "Apply concepts of solution types and expression of concentration"
      ],
      "unit_name": "Unit 1",
      "chapter_name": "Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry Applications",
      "description": "Enable learners to understand electrochemical cells, galvanic cells, Nernst equation, conductance, electrolytic processes, batteries, and corrosion.",
      "competencies": [
        "Analyze functioning of Galvanic Cells and Electrolytic Cells"
      ],
      "unit_name": "Unit 2",
      "chapter_name": "Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics Analysis",
      "description": "Enable learners to analyze factors influencing reaction rates, apply integrated rate equations, and understand temperature dependence via collision theory.",
      "competencies": [
        "Interpret rate of chemical reactions and factors influencing them"
      ],
      "unit_name": "Unit 3",
      "chapter_name": "Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d-and f-Block Elements Properties",
      "description": "Enable learners to understand position in periodic table, electronic configurations of transition elements and inner transition elements (Lanthanoids/Actinoids), and their applications.",
      "competencies": [
        "Correlate general properties of Transition Elements with d-block configuration"
      ],
      "unit_name": "Unit 4",
      "chapter_name": "d-and f-Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Chemistry and Bonding",
      "description": "Enable learners to apply Werner's theory, understand nomenclature, isomerism, bonding in coordination compounds including metal carbonyls.",
      "competencies": [
        "Apply definitions of terms pertaining to Coordination Compounds"
      ],
      "unit_name": "Unit 5",
      "chapter_name": "Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Haloalkanes and Haloarenes Reactivity",
      "description": "Enable learners to classify, name, understand C-X bond nature, preparation methods, physical properties, and chemical reactions of halo compounds.",
      "competencies": [
        "Analyze classification and nomenclature of Haloalkanes"
      ],
      "unit_name": "Unit 6",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Alcohols, Phenols and Ethers Chemistry",
      "description": "Enable learners to classify compounds, understand functional group structures, nomenclature, preparation of alcohols/phenols, ethers.",
      "competencies": [
        "Differentiate between Alcohols, Phenols, and Ethers based on structure"
      ],
      "unit_name": "Unit 7",
      "chapter_name": "Alcohols, Phenols and Ethers"
    },
    {
      "code": "C17",
      "title": "Carbonyl Compounds Chemistry",
      "description": "Enable learners to understand nomenclature of carbonyl groups, preparation methods (aldehydes/ketones/carboxylic acids), physical properties and chemical reactions.",
      "competencies": [
        "Apply knowledge of Carbonyl Group structure and reactivity"
      ],
      "unit_name": "Unit 8",
      "chapter_name": "Aldehydes, Ketones and Carboxylic Acids"
    },
    {
      "code": "C18",
      "title": "Amines Synthesis and Reactivity",
      "description": "Enable learners to understand structure, classification, nomenclature of amines, preparation methods including Diazonium salts synthesis.",
      "competencies": [
        "Analyze chemical reactions involving Amines"
      ],
      "unit_name": "Unit 9",
      "chapter_name": "Amines"
    },
    {
      "code": "C19",
      "title": "Biomolecules and Biochemistry Interface",
      "description": "Enable learners to identify patterns in carbohydrates, proteins, enzymes, vitamins, nucleic acids, hormones, linking chemistry with biology.",
      "competencies": [
        "Classify Biomolecules into Carbohydrates, Proteins, Enzymes, Vitamins"
      ],
      "unit_name": "Unit 10",
      "chapter_name": "Biomolecules"
    }
  ]
}
